// Zobrist hashing constants for fast, incremental position hashing.
// We use 64-bit BigInt keys generated by a deterministic splitmix64 PRNG so the
// table is identical on every load (important for a stable transposition table).

const MASK64 = (1n << 64n) - 1n

function splitmix64(seed: bigint): () => bigint {
  let state = seed & MASK64
  return () => {
    state = (state + 0x9e3779b97f4a7c15n) & MASK64
    let z = state
    z = ((z ^ (z >> 30n)) * 0xbf58476d1ce4e5b9n) & MASK64
    z = ((z ^ (z >> 27n)) * 0x94d049bb133111ebn) & MASK64
    return (z ^ (z >> 31n)) & MASK64
  }
}

const rng = splitmix64(0x00c0ffee_cafef00dn)

// pieces 0..14 (we waste a little space but indexing by raw piece code is clean),
// squares 0..127 (0x88 board). Empty squares are never hashed.
export const PIECE_KEYS: bigint[][] = Array.from({ length: 15 }, () =>
  Array.from({ length: 128 }, () => rng()),
)
export const CASTLE_KEYS: bigint[] = Array.from({ length: 16 }, () => rng())
export const EP_FILE_KEYS: bigint[] = Array.from({ length: 8 }, () => rng())
export const SIDE_KEY: bigint = rng()
